      { q: "What did the Stanford study find about remote work productivity?", opts: ["A five percent decrease.", "No significant change.", "A thirteen percent increase.", "A twenty percent increase."], ans: 2 },
      { q: "According to critics, what declines in remote work settings?", opts: ["Employee retention rates.", "Individual task completion speed.", "Creative problem-solving and complex team projects.", "Compliance with company policies."], ans: 2 },
      { q: "Who may be most disadvantaged by remote work?", opts: ["Senior executives.", "Part-time workers.", "Junior employees.", "Technical specialists."], ans: 2 },
      { q: "What is the typical hybrid model schedule?", opts: ["One day in office, four days remote.", "Two or three days in office per week.", "Alternating weeks in office and remote.", "Full-time office with one remote day."], ans: 1 },
      { q: "What do critics say about the hybrid model?", opts: ["It is too expensive to implement.", "It can create a two-tier culture and scheduling problems.", "It violates employment standards legislation.", "It is only suitable for large corporations."], ans: 1 }
