      { q: "What argument do critics of stronger legislation make?", opts: ["After-hours communication should be encouraged for productivity.", "Some after-hours communication is preferred by workers and adds flexibility.", "Companies should have the right to monitor all communications.", "The legislation will cause companies to move operations overseas."], ans: 1 },
      { q: "What does the speaker identify as the core challenge?", opts: ["Convincing employees to stop checking phones after work.", "Getting all provinces to adopt similar legislation.", "Balancing acknowledgment of technology's impact with avoiding overly rigid policies.", "Funding additional government enforcement of workplace laws."], ans: 2 }
